DROP TABLE IF EXISTS `sl_hubs`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `sl_hubs` (
  `ID` int NOT NULL AUTO_INCREMENT,
  `HUB_NAME` varchar(255) NOT NULL,
  `IS_PICKUP` tinyint(1) DEFAULT '0',
  `IS_DELIVERY` tinyint(1) DEFAULT '0',
  `IS_SORTING` tinyint(1) DEFAULT '0',
  `IS_SOHO` tinyint(1) DEFAULT '0',
  `IS_VIRTUAL` tinyint(1) DEFAULT '0',
  `STATUS` varchar(255) DEFAULT 'active',
  `LAT` decimal(8,6) DEFAULT NULL,
  `LON` decimal(9,6) DEFAULT NULL,
  `CREATED_AT` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `UPDATED_AT` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `IS_C2C_AVAILABLE` tinyint(1) NOT NULL DEFAULT '0',
  `ADDRESS` varchar(1024) DEFAULT NULL,
  `PHONE_NUMBER` varchar(255) DEFAULT NULL,
  `IS_MH` tinyint(1) NOT NULL DEFAULT '0',
  `HUB_TYPE` varchar(128) NOT NULL DEFAULT '3pl',
  `META` text,
  `IS_RMH` tinyint(1) NOT NULL DEFAULT '0',
  `IS_CMH` tinyint(1) NOT NULL DEFAULT '0',
  `GEO_AREA_ID` int DEFAULT NULL,
  `OPERATIONAL_HUB_TYPE` varchar(255) DEFAULT NULL,
  `OPERATIONAL_CODE` varchar(32) DEFAULT NULL,
  `SLA_TIER` varchar(32) DEFAULT NULL,
  `SLA_TARGET` int DEFAULT NULL,
  `ALTERNATE_PHONE_NUMBER` varchar(20) DEFAULT NULL,
  `UNIQUE_IDENTIFIER` varchar(64) DEFAULT NULL,
  `DEFAULT_AREA_ID` int DEFAULT NULL,
  PRIMARY KEY (`ID`),
  UNIQUE KEY `UNIQUE_IDENTIFIER` (`UNIQUE_IDENTIFIER`)
) ENGINE=InnoDB AUTO_INCREMENT=6784 DEFAULT CHARSET=utf8mb3;
/*!40101 SET character_set_client = @saved_cs_client */;

