DROP TABLE IF EXISTS `sl_hub_configs`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `sl_hub_configs` (
  `ID` int NOT NULL AUTO_INCREMENT,
  `HUB_ID` int NOT NULL,
  `HUB_TYPE` varchar(32) NOT NULL DEFAULT 'sub_hub',
  `IS_MH` tinyint(1) NOT NULL DEFAULT '0',
  `ROUTER_OPERATION` tinyint(1) NOT NULL DEFAULT '0',
  `ALL_HUB_OPERATION` tinyint(1) NOT NULL DEFAULT '0',
  `SUB_HUB_OPERATION` tinyint(1) NOT NULL DEFAULT '0',
  `PARENT_CHILD_HUB_OPERATION` tinyint(1) NOT NULL DEFAULT '0',
  `ISD_HUB_OPERATION` tinyint(1) NOT NULL DEFAULT '0',
  `CREATED_AT` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `UPDATED_AT` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`ID`),
  KEY `hub_configs_fk_hub_id` (`HUB_ID`),
  CONSTRAINT `hub_configs_fk_hub_id` FOREIGN KEY (`HUB_ID`) REFERENCES `sl_hubs` (`ID`)
) ENGINE=InnoDB AUTO_INCREMENT=6780 DEFAULT CHARSET=utf8mb3;
