DROP TABLE IF EXISTS `dm_partner_sla_performance`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `dm_partner_sla_performance` (
  `id` int NOT NULL AUTO_INCREMENT,
  `partner_id` int DEFAULT NULL,
  `partner_name` varchar(255) NOT NULL,
  `area_id` int NOT NULL,
  `year` int NOT NULL,
  `month` int NOT NULL,
  `total_deliveries` int NOT NULL DEFAULT '0',
  `late_deliveries` int NOT NULL DEFAULT '0',
  `breach_rate` decimal(5,2) NOT NULL DEFAULT '0.00',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `idx_partner_area_month` (`partner_id`,`area_id`,`year`,`month`),
  KEY `idx_area_id` (`area_id`),
  KEY `idx_partner_id` (`partner_id`)
) ENGINE=InnoDB AUTO_INCREMENT=15152 DEFAULT CHARSET=utf8mb3;
