--
-- Table structure for table `dm_hub_monthly_costs`
--

DROP TABLE IF EXISTS `dm_hub_monthly_costs`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `dm_hub_monthly_costs` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `hub_id` int unsigned NOT NULL COMMENT 'References sl_hubs.ID',
  `year` smallint NOT NULL COMMENT 'e.g. 2025',
  `month` tinyint NOT NULL COMMENT '1 = January â€¦ 12 = December',
  `rent` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT 'Hub space / premises rent',
  `employee_cost` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT 'Total salaries + allowances for hub staff',
  `utility_cost` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT 'Electricity, water, internet',
  `maintenance_cost` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT 'Equipment upkeep, repairs',
  `other_cost` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT 'Any additional operational cost',
  `notes` text COLLATE utf8mb4_unicode_ci COMMENT 'Optional context for this month''s figures',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_hub_year_month` (`hub_id`,`year`,`month`),
  KEY `idx_hub_id` (`hub_id`)
) ENGINE=InnoDB AUTO_INCREMENT=1605 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Monthly fixed + operational cost per hub for profitability modeling';
/*!40101 SET character_set_client = @saved_cs_client */;

